"""Низкочастотный дрейф."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseNoiseclass LowFrequencyDriftNoise(BaseNoise):    name = "Низкочастотный дрейф"    description = "Медленный синусоидальный дрейф со случайной фазой."    params_schema = {        "target_snr_db":   {"type": "float", "default": 10.0,                            "min": -40.0, "max": 80.0,                            "label": "Целевой SNR", "units": "дБ"},        "drift_frequency": {"type": "float", "default": 0.5,                            "min": 1.0e-4, "max": 1.0e3,                            "label": "Частота дрейфа", "units": "Гц"},        "seed":            {"type": "int", "default": 42,                            "min": 0, "max": 2_147_483_647,                            "label": "Seed ГПСЧ"},    }    def _generate_raw(self, clean: Signal, p: dict,                      rng: np.random.Generator) -> np.ndarray:        fd = float(p["drift_frequency"])        nyq = 0.5 * clean.fs        if fd >= nyq:            raise ValueError(                f"drift_frequency={fd} Гц должна быть меньше fs/2={nyq} Гц"            )        phase = float(rng.uniform(0.0, 2.0 * np.pi))        raw = np.sin(2.0 * np.pi * fd * clean.t + phase).astype(np.float64, copy=False)        return raw